#include<bits/stdc++.h>
using namespace std;
int t,m,a,b,c,d;
int gcd(int x,int y)
{
	return y?gcd(y,x%y):x;
}
void print(int x,int y)
{
    int t1=gcd(x,y);
    x/=t1,y/=t1;
    if(y<0) x=-x,y=-y;
    if(x%y==0) cout<<x/y;
    else cout<<x<<'/'<<y;
}
int main()
{
    cin>>t>>m;
    while(t--)
    {
        cin>>a>>b>>c;
        if(a<0) a=-a,b=-b,c=-c;
        d=b*b-4*a*c;
        if(d<0)
        {
            cout<<"NO\n";
            continue;
        }
        int t1=sqrt(d);
        if(t1*t1==d) print((t1-b),(2*a));
        else
        {
            if(b!=0)
            {
                print(-b,2*a);
                cout<<'+';
            }
            int k=1;
            for(int i=2;i<=d/i;i++)
            {
                while(d%(i*i)==0) k*=i,d/=(i*i);
            }
            int t2=gcd(k,2*a);
            int k1=2*a/t2;
            k/=t2;
            if(k>1) cout<<k<<'*';
            cout<<"sqrt("<<d<<')';
            if(k1>1) cout<<'/'<<k1;
        }
        cout<<'\n';
    }
    return 0;
}
